import { db } from '@/lib/db'

// Money helpers — round to 2 decimals for EGP, 6 for USDT
export function roundEgp(n: number): number {
  return Math.round(n * 100) / 100
}
export function roundUsdt(n: number): number {
  return Math.round(n * 1_000_000) / 1_000_000
}

// Format for display
export function formatEgp(n: number): string {
  return new Intl.NumberFormat('en-US', {
    style: 'decimal',
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  }).format(n)
}
export function formatUsdt(n: number): string {
  return new Intl.NumberFormat('en-US', {
    style: 'decimal',
    minimumFractionDigits: 2,
    maximumFractionDigits: 6,
  }).format(n)
}

// Atomic balance update + transaction log
export async function creditEgp(
  userId: string,
  amount: number,
  type: string,
  description: string,
  referenceId?: string,
  referenceType?: string,
) {
  const user = await db.user.findUnique({ where: { id: userId } })
  if (!user) throw new Error('USER_NOT_FOUND')
  const newBalance = roundEgp(Number(user.egpBalance) + amount)
  const [updated] = await db.$transaction([
    db.user.update({
      where: { id: userId },
      data: { egpBalance: newBalance },
    }),
    db.transaction.create({
      data: {
        userId,
        type,
        direction: 'CREDIT',
        currency: 'EGP',
        amount: roundEgp(amount),
        balanceAfter: newBalance,
        description,
        referenceId,
        referenceType,
      },
    }),
  ])
  return updated
}

export async function debitEgp(
  userId: string,
  amount: number,
  type: string,
  description: string,
  referenceId?: string,
  referenceType?: string,
) {
  const user = await db.user.findUnique({ where: { id: userId } })
  if (!user) throw new Error('USER_NOT_FOUND')
  const currentEgp = Number(user.egpBalance)
  if (currentEgp < amount) throw new Error('INSUFFICIENT_EGP_BALANCE')
  const newBalance = roundEgp(currentEgp - amount)
  const [updated] = await db.$transaction([
    db.user.update({
      where: { id: userId },
      data: { egpBalance: newBalance },
    }),
    db.transaction.create({
      data: {
        userId,
        type,
        direction: 'DEBIT',
        currency: 'EGP',
        amount: roundEgp(amount),
        balanceAfter: newBalance,
        description,
        referenceId,
        referenceType,
      },
    }),
  ])
  return updated
}

